import React, { useState, useEffect } from "react";
import logo from "../assets/logo.png";

const slides = [
  {
    image:
      "https://media.licdn.com/dms/image/v2/D5622AQEMb32ut8zXXw/feedshare-shrink_800/feedshare-shrink_800/0/1716679170554?e=2147483647&v=beta&t=eeJOhLSbeKVi0BK3wqlHs-EiFatu1IwrfqHeSNQR3Mw",
    logo: logo,
    title: "La salud es un derecho",
    subtitle: "➡️ Para una vida digna la salud es primordial ⬅️",
  },
  {
    image:
      "https://gacetamedica.com/wp-content/uploads/2023/06/GettyImages-1409041204.jpg",
    logo: logo,
    title: "Pasantías y becas en programa de impacto social",
    subtitle: "➡️ Oportunidades a profesionales y futuros odontólogos ⬅️",
  },

  {
    image:
      "https://uniclinic.es/wp-content/uploads/2023/01/Depositphotos_247055748_S.jpg",
    logo: logo,
    title: "Atención gratuita y personalizada",
    subtitle: "➡️ Jornadas barriales ⬅️",
  },
];

export default function Carousel() {
  const [current, setCurrent] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setCurrent((prev) => (prev + 1) % slides.length);
    }, 5000);

    return () => clearInterval(interval);
  }, []);

  return (
    <div
      style={{
        ...styles.container,
        backgroundImage: `url(${slides[current].image})`,
      }}
    >
      <div style={styles.overlay}>
        <img src={slides[current].logo} alt="logo" style={styles.logo} />

        <h1 style={styles.title}>{slides[current].title}</h1>

        <p style={styles.subtitle}>{slides[current].subtitle}</p>
      </div>
    </div>
  );
}

const styles = {
  container: {
    height: "500px",
    backgroundSize: "cover",
    backgroundPosition: "center",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
  },

  overlay: {
    width: "100%",
    height: "100%",
    backgroundColor: "rgba(0,0,0,0.35)",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    justifyContent: "center",
    color: "white",
    textAlign: "center",
    padding: "2rem",
  },

  logo: {
    width: "400px",
    marginBottom: "0.2rem",
  },

  title: {
    fontSize: "2.2rem",
    fontWeight: "600",
    marginBottom: "0.3rem",
    lineHeight: 1.1,
  },

  subtitle: {
    fontSize: "1.5rem",
    maxWidth: "650px",
    opacity: 0.95,
  },
};
